import { Button, Card, CardContent, CardHeader, Container, Dialog, DialogContent, DialogTitle, Divider, Grid, List, ListItem, makeStyles, Paper, Typography } from '@material-ui/core'
import React from 'react'
import { useState } from 'react'

const useStyle = makeStyles(theme => {
    return {
        title: {
            textAlign: 'center',
            color: '#fefefe'
        },
        answers: {
            border: '1px solid #999',
            borderRadius: '7px',
            marginBottom: theme.spacing(1)
        },
        dialog: {
            backgroundColor: '#162276'
        }
    }
})


export default function Quiz() {
    const classes = useStyle()
    const [quiz, setQuiz] = useState(false);

    const openQuiz = () => {
        setQuiz(true)
    }
    const closeQuiz = () => {
        setQuiz(false)
    }

    const number = 1
    const name = `Quiz ${number}/5`

    return (
        <>
            <Button variant='contained' color='secondary' onClick={openQuiz}>
                Open Dialog
            </Button>
            <Dialog classes={{paper: classes.dialog}} open={quiz} onClose={closeQuiz} fullScreen>
                <Typography variant='h4' className={classes.title}>Web Application Development</Typography>
                <DialogContent>
                    <Card elevation={20} >
                        <Container>
                            <CardHeader title={name} />
                            <CardContent>
                                <Grid container spacing={1}>
                                    
                                    <Grid item xs={12}>
                                        <Typography>
                                            Questions will be here.
                                        </Typography>
                                    </Grid>

                                    <Divider />

                                    <Grid item xs={12}>
                                        <List>
                                            <ListItem className={classes.answers} button >Answers are here</ListItem>
                                            <ListItem className={classes.answers} button >Answers are here</ListItem>
                                            <ListItem className={classes.answers} button >Answers are here</ListItem>
                                            <ListItem className={classes.answers} button >Answers are here</ListItem>
                                        </List>
                                    </Grid>

                                </Grid>
                            </CardContent>
                        </Container>
                    </Card>
                </DialogContent>
            </Dialog>
        </>
    )
}
